import { render } from 'solid-js/web';
import { createSignal, onCleanup } from 'solid-js';
import { cn } from '@/utils/cn';
import { getColor } from '@/utils/helper';
import type { ProgressBarOptions } from './progress-bar.types';

// ─── Internal Bar Component ───────────────────────────────────────────────────

interface BarProps extends Required<ProgressBarOptions> {
  instanceId: string;
  onDone: () => void;
}

const ProgressBarInner = (props: BarProps) => {
  const [progress, setProgress] = createSignal(0);
  const [opacity, setOpacity] = createSignal(1);

  let rafId: number;
  let startTime: number | null = null;

  // Tốc độ ban đầu (% mỗi giây), giảm dần theo hàm mũ
  const INITIAL_SPEED = 28;
  const DECAY = 0.88; // mỗi giây speed *= DECAY
  const MAX_PROGRESS = 99;

  const animate = (timestamp: number) => {
    if (startTime === null) startTime = timestamp;
    const elapsed = (timestamp - startTime) / 1000; // giây

    const speed = INITIAL_SPEED * Math.pow(DECAY, elapsed * 2.5);
    const delta = speed / 60; // per frame (60fps)

    setProgress(prev => {
      const next = prev + delta;
      return next >= MAX_PROGRESS ? MAX_PROGRESS : next;
    });

    if (progress() < MAX_PROGRESS) {
      rafId = requestAnimationFrame(animate);
    }
  };

  rafId = requestAnimationFrame(animate);

  // dismiss() gọi hàm này — jump lên 100% rồi fade out
  const completeAndFade = () => {
    cancelAnimationFrame(rafId);
    setProgress(100);
    setTimeout(() => {
      setOpacity(0);
      setTimeout(() => props.onDone(), props.fadeOutDuration);
    }, 80);
  };

  completionHandlers.set(props.instanceId, completeAndFade);

  onCleanup(function cancelProgressAnimation() {
    cancelAnimationFrame(rafId);
    completionHandlers.delete(props.instanceId);
  });

  const isRtl = () => props.direction === 'rightToLeft';

  const barStyle = () => ({
    width: `${progress()}%`,
    height: `${props.height}px`,
    transition: 'width 0.06s linear',
    'border-radius': props.rounded ? (isRtl() ? '9999px 0 0 9999px' : '0 9999px 9999px 0') : '0',
    'margin-left': isRtl() ? 'auto' : undefined,
  });

  const containerStyle = () => ({
    opacity: opacity(),
    transition: `opacity ${props.fadeOutDuration}ms ease`,
    'z-index': props.zIndex,
    position: 'fixed' as const,
    [props.position === 'bottom' ? 'bottom' : 'top']: '0',
    left: '0',
    right: '0',
    'pointer-events': 'none' as const,
  });

  return (
    <div style={containerStyle()}>
      <div
        class={cn('relative overflow-hidden', getColor(props.color), 'bg-(--color)')}
        style={barStyle()}
      >
        {props.shimmer && (
          <div
            class={cn(
              'absolute inset-0',
              'animate-[shimmer_1.2s_ease-in-out_infinite]',
              'bg-linear-to-r from-transparent via-white/40 to-transparent',
            )}
          />
        )}
      </div>
    </div>
  );
};

// ─── Global state ─────────────────────────────────────────────────────────────

const completionHandlers = new Map<string, () => void>();

// Track tất cả instances đang tồn tại (có thể nhiều hơn 1 trong khoảng thời gian ngắn)
const activeDisposers = new Map<string, () => void>();

let containerEl: HTMLDivElement | null = null;

const ensureContainer = () => {
  if (containerEl) return;
  containerEl = document.createElement('div');
  containerEl.id = 'sui-progress-bar-container';
  document.body.appendChild(containerEl);
};

// Xóa tất cả instances ngay lập tức (không animate)
const disposeAll = () => {
  for (const dispose of activeDisposers.values()) {
    dispose();
  }
  activeDisposers.clear();
};

// ─── Public API ───────────────────────────────────────────────────────────────

export interface ProgressBarAPI {
  start: (options?: ProgressBarOptions) => void;
  dismiss: () => void;
}

const DEFAULT_OPTIONS: Required<ProgressBarOptions> = {
  color: 'primary',
  height: 3,
  shimmer: true,
  rounded: true,
  zIndex: 9999,
  fadeOutDuration: 300,
  position: 'top',
  direction: 'leftToRight',
};

const progressBar: ProgressBarAPI = {
  start(options?: ProgressBarOptions) {
    ensureContainer();

    // Xóa tất cả instances cũ ngay lập tức
    disposeAll();

    const instanceId = Math.random().toString(36).slice(2);

    const mergedOptions: Required<ProgressBarOptions> = {
      ...DEFAULT_OPTIONS,
      ...options,
    };

    const slot = document.createElement('div');
    containerEl!.appendChild(slot);

    const dispose = render(
      () => (
        <ProgressBarInner
          {...mergedOptions}
          instanceId={instanceId}
          onDone={() => {
            dispose();
            slot.remove();
            activeDisposers.delete(instanceId);
          }}
        />
      ),
      slot,
    );

    activeDisposers.set(instanceId, () => {
      dispose();
      slot.remove();
    });
  },

  dismiss() {
    if (activeDisposers.size === 0) return;

    // Lấy tất cả instanceIds hiện tại
    const ids = [...activeDisposers.keys()];

    for (const id of ids) {
      const handler = completionHandlers.get(id);
      if (handler) {
        // Animate lên 100% rồi fade out
        activeDisposers.delete(id);
        handler();
      } else {
        // Fallback: xóa ngay
        const dispose = activeDisposers.get(id);
        activeDisposers.delete(id);
        dispose?.();
      }
    }
  },
};

export { progressBar };
